#include "gtest/gtest.h"
#include "utilities/fims_json.hpp"

#include <sstream>
#include <string>

namespace
{
  // JsonParser_Parse
  // IO correctness
  TEST(JsonParser_Parse, HandlesNumberForms) {
    using fims::JsonParser;
    using fims::JsonValueType;

    JsonParser parser;

    auto integer_json = parser.Parse("-17");
    EXPECT_EQ(integer_json.GetType(), JsonValueType::Number);
    EXPECT_EQ(integer_json.GetInt(), -17);

    auto decimal_json = parser.Parse("3.5");
    EXPECT_EQ(decimal_json.GetType(), JsonValueType::Number);
    EXPECT_NEAR(decimal_json.GetDouble(), 3.5, 1e-12);

    auto scientific_json = parser.Parse("1.2e3");
    EXPECT_EQ(scientific_json.GetType(), JsonValueType::Number);
    EXPECT_NEAR(scientific_json.GetDouble(), 1200.0, 1e-12);
  }

  TEST(JsonParser_Parse, HandlesMixedArrayInput) {
    using fims::JsonParser;
    using fims::JsonValueType;

    JsonParser parser;
    auto json = parser.Parse("[1,\"two\",false,null,{\"k\":9}]");

    EXPECT_EQ(json.GetType(), JsonValueType::JArray);
    auto& arr = json.GetArray();
    // Use fatal assertion, ASSERT_EQ, because the lines after it will fail if
    // the fatal assertion does not work. ASSERT_EQ protects the code and gives
    // a cleaner failure message.
    ASSERT_EQ(arr.size(), 5);
    EXPECT_EQ(arr[0].GetInt(), 1);
    EXPECT_EQ(arr[1].GetString(), "two");
    EXPECT_FALSE(arr[2].GetBool());
    EXPECT_EQ(arr[3].GetType(), JsonValueType::Null);
    EXPECT_EQ(arr[4].GetObject()["k"].GetInt(), 9);
  }

  TEST(JsonParser_Parse, HandlesNestedObjects) {
    using fims::JsonParser;

    JsonParser parser;
    auto json = parser.Parse(
        "{\"outer\":{\"inner\":{\"v\":5}},\"list\":[{\"x\":1},{\"x\":2}]}"
    );

    auto& root = json.GetObject();
    EXPECT_EQ(root["outer"].GetObject()["inner"].GetObject()["v"].GetInt(), 5);
    EXPECT_EQ(root["list"].GetArray()[0].GetObject()["x"].GetInt(), 1);
    EXPECT_EQ(root["list"].GetArray()[1].GetObject()["x"].GetInt(), 2);
  }

  // Edge handling
  TEST(JsonParser_Parse, HandlesObjectWithTrailingWhitespace) {
    using fims::JsonParser;

    JsonParser parser;
    auto json = parser.Parse("{\"a\":1}   \n\t ");

    EXPECT_EQ(json.GetObject()["a"].GetInt(), 1);
  }

  TEST(JsonParser_PrettyFormatJSON, HandlesQuotedPunctuation) {
    using fims::JsonParser;

    const std::string raw = "{\"msg\":\"a,b:c\",\"v\":1}";
    const std::string pretty = JsonParser::PrettyFormatJSON(raw);

    // Characters inside quotes should remain untouched.
    EXPECT_NE(pretty.find("\"a,b:c\""), std::string::npos);
    // Structural punctuation should still trigger formatting behavior.
    EXPECT_NE(pretty.find("\n"), std::string::npos);
    EXPECT_NE(pretty.find("\"v\": 1"), std::string::npos);
  }

  // Error handling
  TEST(JsonParser_Parse, InvalidBooleanTokenReturnsNullValue) {
    using fims::JsonParser;
    using fims::JsonValueType;

    JsonParser parser;
    auto invalid = parser.Parse("fals");

    EXPECT_EQ(invalid.GetType(), JsonValueType::Null);
  }

  TEST(JsonParser_Show, HandlesObjectOutput) {
    using fims::JsonParser;

    JsonParser parser;
    auto json = parser.Parse("{\"a\":1,\"b\":true}");

    std::stringstream captured_cout;
    std::streambuf* old_cout = std::cout.rdbuf(captured_cout.rdbuf());
    parser.Show(json);
    std::cout.rdbuf(old_cout);

    const std::string output = captured_cout.str();
    EXPECT_NE(output.find("\"a\":1"), std::string::npos);
    EXPECT_NE(output.find("\"b\":true"), std::string::npos);
    EXPECT_EQ(output.back(), '\n');
  }
}
